    if (source == target) return 0

    // Collect all unique edge weights to form the search space for binary search
    val weightsSet = new Set[Long]()
    for (edge in edges) {
      val w = edge(2)
      weightsSet.add(w)
    }
    // Include 0 as a potential minimum threshold
    weightsSet.add(0L)

    val sortedWeights = weightsSet.toSeq.sorted

    // Helper function to check if a path exists using at most k heavy edges for a given threshold
    def canReach(threshold: Long): Boolean = {
      // State: [node, heavy_edges_used]

      // visited[node][heavy_count] = true if this state has been reached.
      // k is an integer up to edges.length, which is up to 1000.
      val visited = Array.fill(0.toLong, Array.fill(0.toLong, false))
