/**
 * @param {number} n The number of nodes.
 * @param {number[][]} edges The list of edges [u, v, w].
 * @param {number} source The source node.
 * @param {number} target The target node.
 * @param {number} k The maximum number of heavy edges allowed.
 * @return {number} The minimum threshold, or -1.
 */
const solve = (n, edges, source, target, k) => {
    if (source === target) return 0;

    // Collect all unique edge weights to form the search space for binary search
    const weights = new Set();
    for (const [, , w] of edges) {
        weights.add(w);
    }
    // Include 0 as a potential minimum threshold
    weights.add(0);

    const sortedWeights = Array.from(weights).sort((a, b) => a - b);

    /**
     * Checks if a path exists from source to target using at most k heavy edges,
     * given a specific threshold.
     * @param {number} threshold The weight threshold.
     * @returns {boolean} True if a valid path exists, false otherwise.
     */
    const canReach = (threshold) => {
        // State: [node, heavy_edges_used]
        // We use BFS/Dijkstra-like approach where the state includes the count of heavy edges.

        // dist[i][j] stores the minimum number of edges required to reach node i having used exactly j heavy edges.
        // Since we only care about reachability (existence), a simpler BFS state tracking is sufficient.

        // visited[node][heavy_count] = true if this state has been reached.
        const visited = Array(n).fill(0).map(() => Array(k + 1).fill(false));
        const queue = [];

        // Initial state: [source_node, heavy_count]
        queue.push([source, 0]);
        visited[source][0] = true;

        let head = 0;
        while (head < queue.length) {
            const [u, heavyCount] = queue[head++];

            if (u === target) {
                return true; // Target reached with <= k heavy edges
            }

            for (const [u_edge, v_edge, w_edge] of edges) {
                let neighbor = -1;
                if (u_edge === u) neighbor = v_edge;
                else if (v_edge === u) neighbor = u_edge;
                else continue;

                // Determine if the edge is heavy
                const isHeavy = w_edge > threshold;

                const newHeavyCount = heavyCount + (isHeavy ? 1 : 0);

                if (newHeavyCount <= k && !visited[neighbor][newHeavyCount]) {
                    visited[neighbor][newHeavyCount] = true;
                    queue.push([neighbor, newHeavyCount]);
                }
            }
        }

        return false;
    };

    // Binary Search on the sorted unique weights
    let low = 0;
    let high = sortedWeights.length - 1;
    let minThreshold = -1;

    while (low <= high) {
        const midIndex = Math.floor((low + high) / 2);
        const currentThreshold = sortedWeights[midIndex];

        if (canReach(currentThreshold)) {
            // If reachable, this threshold is a candidate. Try for a smaller one.
            minThreshold = currentThreshold;
            high = midIndex - 1;
        } else {
            // If not reachable, we need a larger threshold (to make more edges "light").
            low = midIndex + 1;
        }
    }

    return minThreshold;
};

