import scala.collection.mutable.ArrayBuffer

def solve(n: Long, edges: Array[Array[Long]], source: Long, target: Long, k: Long): Long = {
  if (source == target) return 0

  val nInt = n.toInt
  val kInt = k.toInt

  // Collect all unique edge weights to form the search space for binary search
  val weights = scala.collection.mutable.HashSet[Long]()
  for (edge of edges) {
    val w = edge(2)
    weights.add(w)
  }
  weights.add(0)

  val sortedWeights = weights.toSeq.sorted

  // Helper function to check reachability for a given threshold
  def canReach(threshold: Long): Boolean = {
    // State: [node, heavy_edges_used]
    // BFS approach

    // visited[node][heavy_count] = true if this state has been reached.
    // Size: n x (k+1)
    val visited = Array.ofDim[Boolean](nInt, kInt + 1).map(_ => Array.fill(kInt + 1)(false))

    // Queue stores [node, heavy_count]
    val queue = ArrayBuffer[(Int, Int)]()

    // Initial state: [source_node, heavy_count]
    queue.append((source.toInt, 0))
    visited(source.toInt)(0) = true

    var head = 0
    while (head < queue.length) {
      val (u, heavyCount) = queue(head)
      head += 1

      if (u == target.toInt) {
        return true // Target reached with <= k heavy edges
      }

      // Iterate over all edges to find neighbors of u
      for (edge of edges) {
        val uEdge = edge(0).toInt
        val vEdge = edge(1).toInt
        val wEdge = edge(2)

        var neighbor = -1
        if (uEdge == u) neighbor = vEdge
        else if (vEdge == u) neighbor = uEdge
        else continue

        // Determine if the edge is heavy
        val isHeavy = wEdge > threshold

        val newHeavyCount = heavyCount + (if (isHeavy) 1 else 0)

        if (newHeavyCount <= kInt && !visited(neighbor)(newHeavyCount)) {
          visited(neighbor)(newHeavyCount) = true
          queue.append((neighbor, newHeavyCount))
        }
      }
    }

    false
  }

  // Binary Search on the sorted unique weights
  var low = 0
  var high = sortedWeights.length - 1
  var minThreshold: Long = -1

  while (low <= high) {
    val midIndex = low + (high - low) / 2
    val currentThreshold = sortedWeights(midIndex)

    if (canReach(currentThreshold)) {
      // If reachable, this threshold is a candidate. Try for a smaller one.
      minThreshold = currentThreshold
      high = midIndex - 1
    } else {
      // If not reachable, we need a larger threshold (to make more edges "light").
      low = midIndex + 1
    }
  }

  minThreshold
}
